export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };

export type QuoteStep = { op: "quote"; items: Item[] };
export type Step = QuoteStep;

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type StepResult = QuoteResult;

export type ScenarioResult = {
  results: StepResult[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_BLOCK_OF_THREE_PREMIUM = 60;

const itemBasePremium = (item: Item): number => MAIN_ITEM_BASE_PREMIUM[item.type];

const policyBasePremium = (items: Item[]): number => {
  if (items.length === 3 && items.every((i) => i.type === "rune"))
    return COMPONENT_BLOCK_OF_THREE_PREMIUM;
  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
};

const quotePremium = (items: Item[]): number => {
  const policyBase = policyBasePremium(items);
  return policyBase + policyBase * FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
};

export const processScenario = (scenario: Scenario): ScenarioResult => {
  const results: StepResult[] = scenario.steps.map((step) => ({
    premium: Math.ceil(quotePremium(step.items)),
  }));
  return { results };
};

