import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office - quote", () => {
  it("returns premium 5 G for an empty item list (only processing fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quotes a single sword for a newcomer at 115 G (100 base + 10 first insurance + 5 fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quotes a single amulet for a newcomer at 71 G (60 + 6 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quotes a single staff for a newcomer at 93 G (80 + 8 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quotes a single potion for a newcomer at 49 G (40 + 4 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });
  it("quotes a single rune component for a newcomer at 33 G (25 + 2.5 + 5, rounded up)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("quotes 2 runes (no block) at 60 G (50 + 5 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quotes 3 alike runes as a building block at 71 G (60 base + 6 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quotes 4 runes (no block, block requires exactly 3) at 115 G (100 + 10 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quotes 7 runes at 198 G (175 + 17.5 + 5, rounded up)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("quotes 2 runes + 1 moonstone without a block at 88 G (75 + 7.5 + 5 = 87.5, rounded up)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("quotes 3 runes + 3 moonstones as two separate blocks at 137 G (120 + 12 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });
  it("applies a 50% curse surcharge to a cursed sword for a newcomer at 165 G", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("applies a 30% high-enchantment surcharge to a sword at enchantment 5 (newcomer) at 145 G (100 + 30 + 10 + 5)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it("applies a 20% loyalty discount for customers with 2+ years (sword, 2 years, first quote) at 95 G (100 - 20 + 10 + 5 = 95)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("applies a 15% follow-up contract discount on the second quote (sword, 0 years, second quote) at 100 G (100 + 10 - 15 + 5 = 100)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] },
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }, { premium: 100 }] });
  });
  it.todo("does not apply high-enchantment surcharge at enchantment 4 (newcomer cursed sword e=4) at 165 G");
  it.todo("applies both curse and high-enchantment surcharges at enchantment 5 for a cursed sword (newcomer) at 195 G (100 + 50 + 30 + 13 + 5)");
  it.todo("applies item-specific modifiers per item on multi-item policies (cursed sword + plain amulet, newcomer) at 236 G (160 + 50 + 16 + 5)");
  it.todo("rounds the final premium up in MHPCO's favor");
  it.todo("integration: newcomer with a cursed sword premium 165 G");
  it.todo("integration: 3-year customer's second quote, cursed sword enchantment 7, premium 160 G");
});

describe("MHPCO Claim Office - claim", () => {
  it.todo("pays out 400 G for damage 500 G to a regular sword (full reimbursement minus 100 G deductible)");
  it.todo("pays out 100 G for damage 200 G to a rune (no special clause applies)");
  it.todo("applies the deductible per damage event on multi-item damages (sword 500 + amulet 300 → 600 G)");
  it.todo("pays only 50% for high-enchantment damage (steel sword e=9, damage 1000 → 400 G)");
  it.todo("fully reimburses dragon-material items (dragon sword e=5, damage 800 → 700 G)");
  it.todo("applies the 50% high-enchantment clause first when both clauses apply (dragon sword e=9, damage 1000 → 400 G)");
  it.todo("caps the total payout at twice the insurance sum across successive claims (sword 1000, two 1500 claims → 1400 then 600)");
  it.todo("rejects a claim referring to an item not in the policy (non-zero exit, error on stderr)");
  it.todo("rejects a claim with negative damage amount (non-zero exit, error on stderr)");
  it.todo("rejects a claim with more damages of a type than items insured of that type");
  it.todo("rounds the final payout down in MHPCO's favor");
});

describe("MHPCO Claim Office - validation", () => {
  it.todo("rejects a quote containing an unknown item type (non-zero exit, error on stderr)");
});

