51	  let mainItemsTotal = 0;
52	  for (const item of items) {
53	    if (isComponent(item)) {
54	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
55	    } else {
56	      mainItemsTotal += itemBasePremium(item);
57	    }
58	  }
59	  const componentsTotal = Object.entries(componentCounts).reduce(
60	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
61	    0,
62	  );
63	  return mainItemsTotal + componentsTotal;
64	};
